+package org.apache.streampipes.client.util;
+
+import java.net.InetAddress;
+import java.net.URI;
+import java.net.URISyntaxException;
+import java.net.UnknownHostException;
+
+/**
+ * Utility class for validating URLs to prevent SSRF attacks.
+ * This validates that URLs don't point to internal or loopback addresses.
+ */
+public class UrlValidation {
+
+  /**
+   * Validate that a URL is safe to request (not pointing to internal/private addresses).
+   * 
+   * @param urlString The URL to validate
+   * @throws IllegalArgumentException if the URL is not safe
+   */
+  public static void validateUrl(String urlString) throws IllegalArgumentException {
+    if (urlString == null || urlString.isEmpty()) {
+      throw new IllegalArgumentException("URL cannot be null or empty");
+    }
+
+    try {
+      URI uri = new URI(urlString);
+      
+      // Only allow http and https protocols
+      String scheme = uri.getScheme();
+      if (scheme == null || (!scheme.equalsIgnoreCase("http") && !scheme.equalsIgnoreCase("https"))) {
+        throw new IllegalArgumentException("Only HTTP and HTTPS protocols are allowed");
+      }
+      
+      // Resolve the hostname to IP address
+      String host = uri.getHost();
+      if (host == null) {
+        throw new IllegalArgumentException("Invalid URL: no host specified");
+      }
+      
+      InetAddress address = InetAddress.getByName(host);
+      
+      // Check for loopback addresses (127.x.x.x, ::1, localhost)
+      if (address.isLoopbackAddress()) {
+        throw new IllegalArgumentException("Loopback addresses are not allowed");
+      }
+      
+      // Check for site-local addresses (private addresses)
+      if (address.isSiteLocalAddress()) {
+        throw new IllegalArgumentException("Site-local (private) addresses are not allowed");
+      }
+      
+      // Check for link-local addresses
+      if (address.isLinkLocalAddress()) {
+        throw new IllegalArgumentException("Link-local addresses are not allowed");
+      }
+      
+      // Check for multicast addresses
+      if (address.isMulticastAddress()) {
+        throw new IllegalArgumentException("Multicast addresses are not allowed");
+      }
+      
+    } catch (URISyntaxException e) {
+      throw new IllegalArgumentException("Invalid URL syntax: " + e.getMessage());
+    } catch (UnknownHostException e) {
+      throw new IllegalArgumentException("Unknown host: " + e.getMessage());
+    }
+  }
+}
