+var uuid = require('uuid');
+
+function generateToken() {
+  return uuid.v4();
+}
+
+function csrfMiddleware(req, res, next) {
+  // Only validate state-changing requests
+  if (['GET', 'HEAD', 'OPTIONS', 'TRACE'].indexOf(req.method.toUpperCase()) !== -1) {
+    return next();
+  }
+  
+  // Check for valid CSRF token
+  var token = req.body && req.body._csrf || req.headers['x-csrf-token'];
+  var sessionToken = req.session && req.session.csrfToken;
+  
+  // Validate token using timing-safe comparison
+  if (token && sessionToken && token.length === sessionToken.length) {
+    var crypto = require('crypto');
+    var diff = crypto.timingSafeEqual(Buffer.from(token), Buffer.from(sessionToken));
+    if (diff) {
+      return next();
+    }
+  }
+  
+  res.status(403);
+  if (req.xhr || req.headers['x-requested-with'] === 'XMLHttpRequest') {
+    return res.json({ error: 'Invalid or missing CSRF token' });
+  }
+  return res.send('403 Forbidden: Invalid or missing CSRF token');
+}
+
+function addCsrfToken(req, res, next) {
+  if (!req.session) {
+    return next();
+  }
+  if (!req.session.csrfToken) {
+    req.session.csrfToken = generateToken();
+  }
+  res.locals = res.locals || {};
+  res.locals.csrfToken = req.session.csrfToken;
+  next();
+}
+
+module.exports = { generateToken: generateToken, csrfMiddleware: csrfMiddleware, addCsrfToken: addCsrfToken };
