+ * Authorization middleware
+ * Ensures requests are properly authenticated and authorized
+ */
+const settings = require('../runtime/settings');
+
+const authorize = (req, res, next) => {
+    // Check if security is enabled
+    if (settings.secureEnabled) {
+        // Verify authentication token exists
+        const token = req.headers.authorization || req.query.token;
+        if (!token) {
+            logger.warn('Unauthorized access attempt: No authentication token provided');
+            return res.status(401).json({ error: 'Authentication required' });
+        }
+
+        // Verify token validity (implementation depends on auth strategy)
+        // This could check JWT, session, or custom token validation
+        const isValid = validateToken(token);
+        if (!isValid) {
+            logger.warn('Unauthorized access attempt: Invalid authentication token');
+            return res.status(403).json({ error: 'Invalid or expired token' });
+        }
+
+        // Attach user info to request for role-based checks
+        req.user = getUserFromToken(token);
+    }
+    // If secureEnabled is false, allow access (maintain backward compatibility)
+    next();
+};
+
+module.exports = { authorize };

